if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $('Webhook').first().json.body || {};
const name = body.name || body.competitor || 'Unknown';
const prompt = ['COMPETITOR ANALYSIS: ' + name, '', 'Search Tavily and USASpending for this competitor. Return JSON with name, size, threat_score, capabilities, known_contracts, overlap_with_eis, teaming_potential, recent_news, eis_strategy, analyzed_at'].join('\n');
return [{ json: { prompt, name, action: 'analyze' } }];

const body = $('Webhook').first().json.body || {};
const name = body.name || body.competitor || 'Unknown';
const question = body.question || 'Tell me about this competitor';
const prompt = ['COMPETITOR QUESTION: ' + name, 'Question: ' + question, 'Search Tavily. Return JSON: {competitor, question, answer, implications_for_eis, sources, answered_at}'].join('\n');
return [{ json: { prompt, name, action: 'ask' } }];

const body = $('Webhook').first().json.body || {};
const competitors = body.competitors || ['Booz Allen Hamilton', 'Leidos', 'SAIC', 'CACI', 'L3Harris'];
const prompt = ['COMPETITOR MONITORING SCAN', '', competitors.map(function(c,i){return (i+1)+'. '+c;}).join('\n'), '', 'Return JSON: {scan_date, alerts, competitors_scanned, total_alerts}'].join('\n');
return [{ json: { prompt, action: 'monitor' } }];

var item = $input.first().json;
var data = item.output || '';
var start = data.indexOf('{');
var end = data.lastIndexOf('}');
var parsed = {};
try { if (start !== -1 && end !== -1) parsed = JSON.parse(data.substring(start, end + 1)); else parsed = { error: 'No JSON found' }; } catch(e) { parsed = { error: 'Parse failed' }; }
if (!parsed.generated_at) parsed.generated_at = new Date().toISOString();
return [{ json: parsed }];

const data = $input.first().json;
let text = '';
if (data.content && data.content[0]) text = data.content[0].text || '';
else if (data.error) text = JSON.stringify(data.error);
else text = JSON.stringify(data);
return [{ json: { output: text } }];
